import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, FaClock, FaStar, FaPrint } from 'react-icons/fa';
import config, { getMaterialTypes } from '../config/config';
import { getMaterialsForSubject } from '../services/api';

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState(false);

  // Mock data - Replace with your API calls
  const MaterialsPage = () => {
  const materialTypes = getMaterialTypes();
  
  return (
    <div>
      {materialTypes.map(type => (
        <div style={{ color: type.color }}>
          {type.icon} {type.name}
        </div>
      ))}
    </div>
  );
};

  const subjectsData = {
    '1': { name: 'Mathematics-I', code: 'MATH101', credits: 4 },
    '2': { name: 'Programming in C', code: 'CSE101', credits: 3 },
    '3': { name: 'Digital Electronics', code: 'ECE101', credits: 4 },
    '4': { name: 'Data Structures', code: 'CSE201', credits: 4 },
  };

  // Material types with icons and colors
  const materialTypes = [
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' },
  ];

  useEffect(() => {
    fetchSubjectData();
  }, [subjectId]);

  const fetchSubjectData = async () => {
    try {
      // Simulate API call
      setTimeout(() => {
        const subjectData = subjectsData[subjectId] || {
          name: 'Subject Name',
          code: 'SUB101',
          credits: 3
        };

        setSubject(subjectData);

        // Mock materials data
        const mockMaterials = [
          // Syllabus
          {
            id: 1,
            title: 'Complete Syllabus 2024',
            type: 'syllabus',
            description: 'Official syllabus with unit-wise distribution',
            fileSize: '1.2 MB',
            pages: 12,
            uploadDate: '2024-01-15',
            downloads: 245,
            rating: 4.5,
            isNew: true,
            fileUrl: '#'
          },
          {
            id: 2,
            title: 'Syllabus with Marking Scheme',
            type: 'syllabus',
            description: 'Includes chapter-wise marks distribution',
            fileSize: '0.8 MB',
            pages: 8,
            uploadDate: '2024-01-10',
            downloads: 189,
            rating: 4.2,
            fileUrl: '#'
          },

          // Notes
          {
            id: 3,
            title: 'Complete Notes - Unit 1 to 5',
            type: 'notes',
            description: 'Handwritten notes with diagrams and examples',
            fileSize: '4.5 MB',
            pages: 45,
            uploadDate: '2024-01-20',
            downloads: 420,
            rating: 4.8,
            isNew: true,
            fileUrl: '#'
          },
          {
            id: 4,
            title: 'Short Notes for Revision',
            type: 'notes',
            description: 'Concise notes for last minute revision',
            fileSize: '2.1 MB',
            pages: 25,
            uploadDate: '2024-01-18',
            downloads: 312,
            rating: 4.3,
            fileUrl: '#'
          },
          {
            id: 5,
            title: 'Topic-wise Notes',
            type: 'notes',
            description: 'Detailed notes for each topic',
            fileSize: '5.2 MB',
            pages: 52,
            uploadDate: '2024-01-12',
            downloads: 278,
            rating: 4.6,
            fileUrl: '#'
          },

          // PYQs
          {
            id: 6,
            title: 'PYQ 2020-2023',
            type: 'pyq',
            description: 'Previous year questions with solutions',
            fileSize: '3.2 MB',
            pages: 35,
            uploadDate: '2024-01-05',
            downloads: 520,
            rating: 4.9,
            isNew: true,
            fileUrl: '#'
          },
          {
            id: 7,
            title: 'Solved Question Papers',
            type: 'pyq',
            description: '5 years solved papers',
            fileSize: '4.8 MB',
            pages: 48,
            uploadDate: '2024-01-08',
            downloads: 410,
            rating: 4.7,
            fileUrl: '#'
          },

          // Important Questions
          {
            id: 8,
            title: 'Important Questions Set 1',
            type: 'important',
            description: 'Most expected questions for exams',
            fileSize: '1.5 MB',
            pages: 18,
            uploadDate: '2024-01-22',
            downloads: 380,
            rating: 4.4,
            fileUrl: '#'
          },

          // Lab Manuals
          {
            id: 9,
            title: 'Complete Lab Manual',
            type: 'lab',
            description: 'All experiments with code and output',
            fileSize: '6.2 MB',
            pages: 65,
            uploadDate: '2024-01-14',
            downloads: 290,
            rating: 4.5,
            fileUrl: '#'
          },

          // Assignments
          {
            id: 10,
            title: 'Semester Assignments',
            type: 'assignment',
            description: 'All assignments with solutions',
            fileSize: '2.8 MB',
            pages: 32,
            uploadDate: '2024-01-16',
            downloads: 210,
            rating: 4.2,
            fileUrl: '#'
          },
        ];

        setMaterials(mockMaterials);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching subject data:', error);
      setLoading(false);
    }
  };

  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };

  const handleDownload = async (material) => {
    setDownloading(true);
    // Simulate download
    setTimeout(() => {
      alert(`Downloading: ${material.title}`);
      setDownloading(false);
    }, 1000);
  };

  const handlePreview = (material) => {
    // Implement preview functionality
    alert(`Preview: ${material.title}`);
  };

  const filteredMaterials = selectedType === 'all' 
    ? materials 
    : materials.filter(m => m.type === selectedType);

  const getMaterialStats = () => {
    const stats = {};
    materialTypes.forEach(type => {
      const count = materials.filter(m => m.type === type.id).length;
      stats[type.id] = count;
    });
    return stats;
  };

  const materialStats = getMaterialStats();

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p>Loading study materials...</p>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      {/* Back Button */}
      <button onClick={handleBack} style={styles.backButton}>
        <FaArrowLeft /> Back to Subjects
      </button>

      {/* Subject Header */}
      <div style={styles.subjectHeader}>
        <div style={styles.subjectIconContainer}>
          <div style={styles.subjectIcon}>📖</div>
        </div>
        <div style={styles.subjectInfo}>
          <h1 style={styles.subjectName}>{subject.name}</h1>
          <p style={styles.subjectCode}>Code: {subject.code} • Credits: {subject.credits}</p>
          <div style={styles.breadcrumb}>
            <span>Course {courseId}</span> › 
            <span>Year {yearId}</span> › 
            <span>Sem {semId}</span> › 
            <span style={styles.currentBreadcrumb}>{subject.name}</span>
          </div>
        </div>
      </div>

      {/* Material Type Filter */}
      <div style={styles.filterSection}>
        <h3 style={styles.filterTitle}>Filter by Material Type:</h3>
        <div style={styles.filterButtons}>
          <button
            style={{
              ...styles.filterButton,
              ...(selectedType === 'all' ? styles.filterButtonActive : {})
            }}
            onClick={() => setSelectedType('all')}
          >
            All Materials ({materials.length})
          </button>
          {materialTypes.map(type => (
            <button
              key={type.id}
              style={{
                ...styles.filterButton,
                ...(selectedType === type.id ? styles.filterButtonActive : {}),
                borderLeft: `4px solid ${type.color}`
              }}
              onClick={() => setSelectedType(type.id)}
            >
              <span style={{ marginRight: '8px', color: type.color }}>
                {type.icon}
              </span>
              {type.name} ({materialStats[type.id] || 0})
            </button>
          ))}
        </div>
      </div>

      {/* Materials Grid */}
      <div style={styles.materialsContainer}>
        <h3 style={styles.materialsTitle}>
          {selectedType === 'all' ? 'All Study Materials' : 
           materialTypes.find(t => t.id === selectedType)?.name + ' Only'}
          <span style={styles.materialsCount}> ({filteredMaterials.length} files)</span>
        </h3>

        {filteredMaterials.length === 0 ? (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}>📭</div>
            <h3>No materials found!</h3>
            <p>Materials will be added soon for this subject.</p>
          </div>
        ) : (
          <div style={styles.materialsGrid}>
            {filteredMaterials.map(material => {
              const typeInfo = materialTypes.find(t => t.id === material.type);
              
              return (
                <div key={material.id} style={styles.materialCard}>
                  {/* Material Header */}
                  <div style={styles.materialHeader}>
                    <div style={{
                      ...styles.materialTypeBadge,
                      background: typeInfo?.color + '20',
                      borderLeft: `4px solid ${typeInfo?.color}`
                    }}>
                      <span style={{ color: typeInfo?.color, marginRight: '6px' }}>
                        {typeInfo?.icon}
                      </span>
                      {typeInfo?.name}
                    </div>
                    {material.isNew && (
                      <div style={styles.newBadge}>
                        NEW
                      </div>
                    )}
                  </div>

                  {/* Material Content */}
                  <div style={styles.materialContent}>
                    <h4 style={styles.materialTitle}>{material.title}</h4>
                    <p style={styles.materialDescription}>{material.description}</p>
                    
                    {/* Material Stats */}
                    <div style={styles.materialStats}>
                      <span style={styles.statItem}>
                        <FaClock /> {material.uploadDate}
                      </span>
                      <span style={styles.statItem}>
                        <FaDownload /> {material.downloads}
                      </span>
                      <span style={styles.statItem}>
                        <FaStar /> {material.rating}
                      </span>
                      <span style={styles.statItem}>
                        📄 {material.fileSize}
                      </span>
                      <span style={styles.statItem}>
                        📖 {material.pages} pages
                      </span>
                    </div>
                  </div>

                  {/* Action Buttons */}
                  <div style={styles.actionButtons}>
                    <button
                      style={styles.previewButton}
                      onClick={() => handlePreview(material)}
                    >
                      <FaEye /> Preview
                    </button>
                    <button
                      style={styles.downloadButton}
                      onClick={() => handleDownload(material)}
                      disabled={downloading}
                    >
                      {downloading ? (
                        <>
                          <div style={styles.spinner}></div> Downloading...
                        </>
                      ) : (
                        <>
                          <FaDownload /> Download
                        </>
                      )}
                    </button>
                    <button
                      style={styles.printButton}
                      onClick={() => window.print()}
                    >
                      <FaPrint />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Quick Stats */}
      <div style={styles.quickStats}>
        <h3>📊 Quick Stats</h3>
        <div style={styles.statsGrid}>
          {materialTypes.map(type => (
            <div key={type.id} style={styles.statCard}>
              <div style={{
                ...styles.statIcon,
                background: type.color + '20',
                color: type.color
              }}>
                {type.icon}
              </div>
              <div style={styles.statContent}>
                <h4>{materialStats[type.id] || 0}</h4>
                <p>{type.name}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Footer Note */}
      <div style={styles.footerNote}>
        <p>
          <strong>💡 Tip:</strong> Download materials for offline study. All materials are regularly updated.
          Need specific content? Request via email.
        </p>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh',
